contracts/base/Registry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity =0.8.27;

import {IRegistry} from "./IRegistry.sol";
import {IACLManager} from "./IACLManager.sol";
import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract Registry is IRegistry {
    mapping(bytes4 service => address impl) private _impls;
    IACLManager private immutable _aclManager;
    IERC20 private immutable _athToken;

    address private _deployer;
    uint64 private _version = 0;

    modifier onlyInitializing() {
        require(_version == 0, "Registry: initialized");
        _;
    }

    constructor(IACLManager aclManager, IERC20 athToken) {
        _deployer = msg.sender;
        _aclManager = aclManager;
        _athToken = athToken;
    }

    /// @notice Initialize the registry with the given services and implementations
    /// @param services the list of service typeids
    /// @param impls the list of implementation addresses
    function initialize(bytes4[] memory services, address[] memory impls) public onlyInitializing {
        initSetup(services, impls);
        _version = 1;
        _deployer = address(0);
        emit Initialized();
    }

    /// @notice Initialize the registry with the given services and implementations
    /// @param services the list of service typeids
    /// @param impls the list of implementation addresses
    /// @dev only use this function if service list is too long for a single call,
    /// otherwise use `initialize`. This function is only callable by the deployer
    function initSetup(bytes4[] memory services, address[] memory impls) public onlyInitializing {
        require(_deployer == msg.sender, "Registry: not deployer");
        require(services.length == impls.length, "Registry: input length mismatch");
        for (uint256 i = 0; i < services.length; i++) {
            _impls[services[i]] = impls[i];
        }

        emit SetUp(services, impls);
    }

    /// @inheritdoc IRegistry
    function getACLManager() external view override returns (IACLManager) {
        return _aclManager;
    }

    /// @inheritdoc IRegistry
    function getATHToken() external view override returns (IERC20) {
        return _athToken;
    }

    /// @inheritdoc IRegistry
    function getAddress(bytes4 service) external view override returns (address) {
        return _impls[service];
    }

    /// @inheritdoc IRegistry
    /// @dev only contract deployed by deployer can self-register during initialization
    function register(bytes4 service) external override onlyInitializing {
        // solhint-disable-next-line avoid-tx-origin
        require(_deployer == tx.origin, "Registry: not deployer");
        require(_impls[service] == address(0), "Registry: service exists");
        _impls[service] = msg.sender;
        emit SetAddress(service, msg.sender);
    }

    /// @inheritdoc IRegistry
    /// @dev only migrator can set new implementation addresses
    function setAddress(bytes4 service, address impl) external override {
        _aclManager.requireMigrator(msg.sender);
        _impls[service] = impl;
        emit SetAddress(service, impl);
    }

    /// @inheritdoc IRegistry
    function getVersion() external view override returns (uint64) {
        return _version;
    }

    /// @inheritdoc IRegistry
    function setVersion(uint64 value) external override {
        require(value != 0, "Registry: invalid version");
        _aclManager.requireMigrator(msg.sender);
        _version = value;
        emit SetVersion(value);
    }
}

contracts/base/RequestVerifier.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity =0.8.27;

import {
    IRegistry,
    IRequestVerifier,
    IEmergencySwitch,
    IBlackListManager,
    IUserStorage,
    BaseService,
    REQUEST_VERIFIER_ID,
    EMERGENCY_SWITCH_ID,
    BLACKLIST_MANAGER_ID,
    USER_STORAGE_ID
} from "../Index.sol";
import {ECDSA} from "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import {MessageHashUtils} from "@openzeppelin/contracts/utils/cryptography/MessageHashUtils.sol";

contract RequestVerifier is IRequestVerifier, BaseService {
    constructor(IRegistry registry) BaseService(registry, REQUEST_VERIFIER_ID) {}

    /// @inheritdoc IRequestVerifier
    function checkRisk(bytes4 method, address sender) public view override {
        require(_emegencySwitch().isAllowed(method), "EmergencyPaused");
        require(_blackList().isAllowed(sender, method), "BlackListed");
    }

    /// @inheritdoc IRequestVerifier
    function verify(
        VerifiableData calldata vdata,
        address caller,
        bytes4 method
    ) external override returns (bytes32 hash) {
        require(vdata.sender == caller, "SenderMismatch");
        require(vdata.target == msg.sender, "TargetMismatch");
        require(vdata.method == method, "MethodMismatch");
        require(vdata.version == _registry.getVersion(), "InvalidVersion");
        require(vdata.deadline >= block.timestamp, "DataExpired");

        checkRisk(method, vdata.sender);

        IUserStorage db = IUserStorage(_registry.getAddress(USER_STORAGE_ID));
        IUserStorage.UserData memory user = db.getUserData(vdata.sender);

        require(vdata.nonce > user.nonce, "NonceTooLow");
        // slither-disable-next-line timestamp
        require(vdata.lastUpdateBlock >= user.lastUpdateBlock, "DataTooOld");

        hash = getHash(vdata);
        checkValidatorSignatures(hash, vdata.proof);

        // update user data
        user.nonce = vdata.nonce;
        user.lastUpdateBlock = uint64(block.number);
        db.setUserData(vdata.sender, user);
    }

    /// @inheritdoc IRequestVerifier
    function verifyInitiator(
        VerifiableData calldata vdata,
        bytes4 method
    ) external view override returns (bytes32 hash) {
        require(vdata.target == msg.sender, "TargetMismatch");
        require(vdata.method == method, "MethodMismatch");
        require(vdata.version == _registry.getVersion(), "InvalidVersion");
        require(vdata.deadline >= block.timestamp, "DataExpired");

        hash = getHash(vdata);
        checkInitiatorSignatures(hash, vdata.proof);
    }

    /// @inheritdoc IRequestVerifier
    function getHash(VerifiableData calldata vdata) public view returns (bytes32) {
        return
            keccak256(
                abi.encode(
                    block.chainid,
                    vdata.nonce,
                    vdata.deadline,
                    vdata.lastUpdateBlock,
                    vdata.version,
                    vdata.sender,
                    vdata.target,
                    vdata.params,
                    vdata.payloads
                )
            );
    }

    function checkValidatorSignatures(bytes32 dataHash, bytes calldata signatures) public view {
        uint8 threshold = _registry.getACLManager().getRequiredSignatures();
        require(signatures.length >= (threshold * 65), "Invalid signature len");
        bytes32 hash = MessageHashUtils.toEthSignedMessageHash(dataHash);
        address[] memory signers = new address[](threshold);
        for (uint256 i = 0; i < threshold; i++) {
            signers[i] = ECDSA.recover(hash, signatures[i * 65:(i + 1) * 65]);
            _registry.getACLManager().requireValidator(signers[i]);
            for (uint256 j = 0; j < i; j++) {
                require(signers[j] != signers[i], "Duplicate signer");
            }
        }
    }

    function checkInitiatorSignatures(bytes32 dataHash, bytes calldata signatures) public view {
        uint8 threshold = _registry.getACLManager().getRequiredInitiatorSignatures();
        require(signatures.length >= (threshold * 65), "Invalid signature len");
        bytes32 hash = MessageHashUtils.toEthSignedMessageHash(dataHash);
        address[] memory signers = new address[](threshold);
        for (uint256 i = 0; i < threshold; i++) {
            signers[i] = ECDSA.recover(hash, signatures[i * 65:(i + 1) * 65]);
            _registry.getACLManager().requireInitSettlementOperator(signers[i]);
            for (uint256 j = 0; j < i; j++) {
                require(signers[j] != signers[i], "Duplicate signer");
            }
        }
    }

    /// @dev Get the emergency switch contract from the registry
    function _emegencySwitch() private view returns (IEmergencySwitch) {
        return IEmergencySwitch(_registry.getAddress(EMERGENCY_SWITCH_ID));
    }

    /// @dev Get the black list contract from the registry
    function _blackList() private view returns (IBlackListManager) {
        return IBlackListManager(_registry.getAddress(BLACKLIST_MANAGER_ID));
    }
}

