contracts/slash/SlashHandler.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity =0.8.27;

import {
    IRegistry,
    ISlashHandler,
    ISlashStorage,
    ISlashConfigurator,
    IVestingHandler,
    ISlashDeductionReceiver,
    IStakeHandler,
    VestingRecord,
    IAccountStorage,
    BaseService,
    SLASH_HANDLER_ID,
    SLASH_DEDUCTION_RECEIVER_ID,
    SLASH_STORAGE_ID,
    SLASH_CONFIGURATOR_ID,
    TICKET_MANAGER_ID,
    VESTING_HANDLER_ID,
    ACCOUNT_STORAGE_ID,
    STAKE_HANDLER_ID,
    GRANT_POOL_ID
} from "../Index.sol";
import {SafeERC20, IERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/// @title SlashHandler
/// @notice Executes penalty logic.
contract SlashHandler is ISlashHandler, BaseService {
    using SafeERC20 for IERC20;

    /// @notice Modifier to restrict access to the current Slash Handler
    modifier onlyTicketManager() {
        require(_registry.getAddress(TICKET_MANAGER_ID) == msg.sender, "SlashHandler: TicketManager only");
        _;
    }

    constructor(IRegistry registry) BaseService(registry, SLASH_HANDLER_ID) {}

    /// @notice Deducts penalty from the ticket.
    function createTicket(
        uint256 tid,
        uint256 gid,
        uint256 container,
        uint256 amount
    ) external override onlyTicketManager {
        require(amount > 0, "Invalid amount");
        _slashStorage().increaseTicket(tid, gid, container, amount);
    }

    /// @notice Deducts penalty from the ticket.
    function settlePenalty(
        uint256 tid,
        uint256 gid,
        uint256 container,
        address caller
    ) external override onlyTicketManager returns (uint256) {
        ISlashStorage.Penalty memory penalty = _slashStorage().getTicket(tid, gid, container);
        require(penalty.amount > 0, "Invalid amount");
        address host = _accountStorage().getWallet(tid);
        require(host == caller, "Invalid sender");
        require(host != address(0), "Invalid tid");
        _registry.getATHToken().safeTransferFrom(
            host,
            _registry.getAddress(SLASH_DEDUCTION_RECEIVER_ID),
            penalty.amount
        );

        _slashStorage().decreaseTicket(tid, gid, container, penalty.amount);

        return penalty.amount;
    }

    /// @notice Deducts penalty from the ticket.
    function cancelPenalty(
        uint256 tid,
        uint256 gid,
        uint256 container,
        uint256 amount
    ) external override onlyTicketManager {
        ISlashStorage.Penalty memory penalty = _slashStorage().getTicket(tid, gid, container);
        require(penalty.amount >= amount, "Invalid amount");

        _slashStorage().decreaseTicket(tid, gid, container, amount);
    }

    /// @notice Deducts penalty from the ticket.
    function deductPenalty(
        uint256 tid,
        uint256 gid,
        uint256 container,
        VestingRecord calldata fees,
        VestingRecord calldata rewards
    ) external override onlyTicketManager returns (uint256 amount, uint256 stakedAmount) {
        ISlashStorage.Penalty memory penalty = _slashStorage().getTicket(tid, gid, container);
        require(penalty.amount > 0, "Invalid amount");
        require(penalty.ts + _configurator().getTicketExpireTime() < block.timestamp, "Ticket is not expired");

        amount = 0;
        stakedAmount = 0;

        for (uint256 i = 0; i < fees.amounts.length; i++) {
            amount += fees.amounts[i];
        }
        for (uint256 i = 0; i < rewards.amounts.length; i++) {
            amount += rewards.amounts[i];
        }

        require(amount > 0, "Invalid amount");
        require(amount <= penalty.amount, "Deduction exceeds ticket amount");

        if(amount < penalty.amount) {
            stakedAmount = penalty.amount - amount;
        }


        _vestingHandler().settleSlash(tid, gid, fees, rewards);
        _slashStorage().decreaseTicket(tid, gid, container, penalty.amount);

        if (stakedAmount > 0) {
            _stakeHandler().deductStaked(tid, gid, container, stakedAmount);
        }

        return (amount, stakedAmount);
    }

    /// @notice Refunds tenants for a penalty.
    function refundTenants(
        uint256[] memory tids,
        uint256[] memory amounts
    ) external override onlyTicketManager returns (uint256 totalAmount) {
        require(tids.length > 0, "Empty input");
        require(tids.length == amounts.length, "Invalid length");
        totalAmount = 0;

        for (uint256 i = 0; i < tids.length; i++) {
            require(amounts[i] > 0, "Invalid amount");
            totalAmount += amounts[i];
        }

        _deductionReceiver().sendSlashToken(_registry.getAddress(GRANT_POOL_ID), totalAmount);
    }

    /// @notice Returns the slash deduction receiver contract.
    function _deductionReceiver() internal view returns (ISlashDeductionReceiver) {
        return ISlashDeductionReceiver(_registry.getAddress(SLASH_DEDUCTION_RECEIVER_ID));
    }

    /// @notice Returns the slash handler contract.
    function _slashStorage() internal view returns (ISlashStorage) {
        return ISlashStorage(_registry.getAddress(SLASH_STORAGE_ID));
    }

    /// @notice Returns the slash configurator contract.
    function _configurator() internal view returns (ISlashConfigurator) {
        return ISlashConfigurator(_registry.getAddress(SLASH_CONFIGURATOR_ID));
    }

    /// @notice Returns the vesting handler contract.
    function _vestingHandler() internal view returns (IVestingHandler) {
        return IVestingHandler(_registry.getAddress(VESTING_HANDLER_ID));
    }

    function _accountStorage() internal view returns (IAccountStorage) {
        return IAccountStorage(_registry.getAddress(ACCOUNT_STORAGE_ID));
    }

    function _stakeHandler() internal view returns (IStakeHandler) {
        return IStakeHandler(_registry.getAddress(STAKE_HANDLER_ID));
    }
}

contracts/slash/SlashStorage.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity =0.8.27;

import {IRegistry, ISlashStorage, BaseService, SLASH_STORAGE_ID, SLASH_HANDLER_ID} from "../Index.sol";

/// @title SlashStorage
/// @notice Stores penalty records.
contract SlashStorage is ISlashStorage, BaseService {
    mapping(uint256 tid => mapping(uint256 gid => mapping(uint256 container => Penalty))) private _penalties;
    mapping(uint256 tid => uint256 totalAmount) private _totalAmounts;

    /// @notice Modifier to restrict access to the current Slash Handler
    modifier onlyHandler() {
        require(_registry.getAddress(SLASH_HANDLER_ID) == msg.sender, "SlashStorage: handler only");
        _;
    }

    constructor(IRegistry registry) BaseService(registry, SLASH_STORAGE_ID) {}

    /// @inheritdoc ISlashStorage
    function increaseTicket(uint256 tid, uint256 gid, uint256 container, uint256 amount) external override onlyHandler {
        require(amount > 0, "Invalid amount");
        Penalty storage penalty = _penalties[tid][gid][container];
        if (penalty.amount == 0) {
            penalty.ts = block.timestamp;
        }
        penalty.amount += amount;
        _totalAmounts[tid] += amount;
    }

    /// @inheritdoc ISlashStorage
    function decreaseTicket(uint256 tid, uint256 gid, uint256 container, uint256 amount) external override onlyHandler {
        require(amount > 0, "Invalid amount");
        Penalty storage penalty = _penalties[tid][gid][container];
        penalty.amount -= amount;
        _totalAmounts[tid] -= amount;
    }

    /// @inheritdoc ISlashStorage
    function deleteTicket(uint256 tid, uint256 gid, uint256 container) external override onlyHandler {
        _totalAmounts[tid] -= _penalties[tid][gid][container].amount;
        delete _penalties[tid][gid][container];
    }

    /// @inheritdoc ISlashStorage
    function getTicket(uint256 tid, uint256 gid, uint256 container) external view override returns (Penalty memory) {
        return _penalties[tid][gid][container];
    }

    /// @inheritdoc ISlashStorage
    function totalPenalty(uint256 tid) external view override returns (uint256) {
        return _totalAmounts[tid];
    }
}

contracts/slash/TicketManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity =0.8.27;

import {
    IRegistry,
    ITicketManager,
    IRequestVerifier,
    ISlashHandler,
    VestingRecord,
    BaseService,
    TICKET_MANAGER_ID,
    SLASH_HANDLER_ID
} from "../Index.sol";

/// @title TicketManager
/// @notice Manages the creation and tracking of tickets for penalties.
contract TicketManager is ITicketManager, BaseService {
    constructor(IRegistry registry) BaseService(registry, TICKET_MANAGER_ID) {}

    /// @inheritdoc ITicketManager
    function addPenalty(IRequestVerifier.VerifiableData calldata vdata) external override {
        bytes32 vhash = _verifier().verify(vdata, msg.sender, this.addPenalty.selector);
        (uint256 tid, uint256 gid, uint256 amount, uint256 container) = abi.decode(
            vdata.params,
            (uint256, uint256, uint256, uint256)
        );

        _slashHandler().createTicket(tid, gid, container, amount);
        emit TicketCreated(tid, gid, container, amount, vdata.nonce, vhash);
    }

    /// @inheritdoc ITicketManager
    // pay penalty
    function settlePenalty(IRequestVerifier.VerifiableData calldata vdata) external override {
        bytes32 vhash = _verifier().verify(vdata, msg.sender, this.settlePenalty.selector);
        (uint256 tid, uint256 gid, uint256 container) = abi.decode(vdata.params, (uint256, uint256, uint256));

        uint256 amount = _slashHandler().settlePenalty(tid, gid, container, msg.sender);
        emit TicketSettled(tid, gid, container, amount, vdata.nonce, vhash);
    }

    /// @inheritdoc ITicketManager
    function deductPenalty(IRequestVerifier.VerifiableData calldata vdata) external override {
        bytes32 vhash = _verifier().verify(vdata, msg.sender, this.deductPenalty.selector);
        (uint256 tid, uint256 gid, uint256 container, VestingRecord memory fees, VestingRecord memory rewards) = abi
            .decode(vdata.params, (uint256, uint256, uint256, VestingRecord, VestingRecord));

        (uint256 amount, uint256 stakedAmount) = _slashHandler().deductPenalty(tid, gid, container, fees, rewards);
        emit TicketDeducted(tid, gid, container, amount, stakedAmount, vdata.nonce, vhash);
    }

    /// @inheritdoc ITicketManager
    function cancelPenalty(IRequestVerifier.VerifiableData calldata vdata) external override {
        bytes32 vhash = _verifier().verify(vdata, msg.sender, this.cancelPenalty.selector);
        (uint256 tid, uint256 gid, uint256 container, uint256 amount) = abi.decode(
            vdata.params,
            (uint256, uint256, uint256, uint256)
        );

        _slashHandler().cancelPenalty(tid, gid, container, amount);
        emit TicketCancelled(tid, gid, container, amount, vdata.nonce, vhash);
    }

    /// @inheritdoc ITicketManager
    function refundTenants(IRequestVerifier.VerifiableData calldata vdata) external override {
        bytes32 vhash = _verifier().verify(vdata, msg.sender, this.refundTenants.selector);
        (uint256[] memory tids, uint256[] memory amounts) = abi.decode(vdata.params, (uint256[], uint256[]));

        uint256 totalAmount = _slashHandler().refundTenants(tids, amounts);

        emit TenantRefunded(tids, amounts, totalAmount, vdata.nonce, vhash);
    }

    /// @notice Returns the slash handler contract.
    function _slashHandler() private view returns (ISlashHandler) {
        return ISlashHandler(_registry.getAddress(SLASH_HANDLER_ID));
    }
}

