    VESTING_FUND_HOLDER_ID,
    VESTING_HANDLER_ID,
    VESTING_PENALTY_RECEIVER_ID,
    SLASH_DEDUCTION_RECEIVER_ID,
    RESTAKE_FEE_RECEIVER_ID,
    STAKE_FUND_HOLDER_ID
} from "../Index.sol";
