// SPDX-License-Identifier: MIT
pragma solidity =0.8.27;

import {IRegistry, IVestingSchemeManager, VestingType, BaseService, VESTING_SCHEME_MANAGER_ID} from "../Index.sol";

contract VestingSchemeManager is IVestingSchemeManager, BaseService {
    mapping(VestingType => uint32[]) private _percentages;
    mapping(VestingType => uint32[]) private _dates;

    constructor(IRegistry registry) BaseService(registry, VESTING_SCHEME_MANAGER_ID) {
        // service_fee_vesting_time - default = 45 days
        _percentages[VestingType.ServiceFee] = [100];
        _dates[VestingType.ServiceFee] = [45];
        // unstake_vesting_time - default 180 days
        _percentages[VestingType.Unstake] = [100];
        _dates[VestingType.Unstake] = [180];
        // reward_first_portion_percentage - default 30
        // reward_second_portion_percentage - default 30
        // reward_first_portion_vesting_time - default 0 days
        // reward_second_portion_vesting_time - default 90 days
        // reward_third_portion_vesting_time - default 180 days
        _percentages[VestingType.Reward] = [30, 30, 40];
        _dates[VestingType.Reward] = [0, 90, 180];
    }

    /// @inheritdoc IVestingSchemeManager
    function setVestingScheme(
        VestingType vestingType,
        uint32[] memory percentages,
        uint32[] memory dates
    ) external override {
        _registry.getACLManager().requireConfigurationAdmin(msg.sender);
        require(percentages.length == dates.length, "InputLengthMismatch");
        uint256 totalPercentage;
        for (uint256 i = 0; i < percentages.length; i++) {
            totalPercentage += percentages[i];
        }
        require(totalPercentage == 100, "TotalPercentage!=100");
        _percentages[vestingType] = percentages;
        _dates[vestingType] = dates;
        emit VestingSchemeSet(vestingType, percentages, dates);
    }

    /// @inheritdoc IVestingSchemeManager
    function getVestingScheme(
        VestingType vestingType
    ) external view override returns (uint32[] memory, uint32[] memory) {
        return (_percentages[vestingType], _dates[vestingType]);
    }

    /// @inheritdoc IVestingSchemeManager
    function getVestingAmount(
        VestingType vestingType,
        uint256 amount
    ) external view override returns (uint256[] memory, uint32[] memory) {
        require(amount > 0, "Invalid amount");
        uint32 _today = today();
        uint32[] memory percentages = _percentages[vestingType];
        uint32[] memory vestingDays = new uint32[](percentages.length);
        uint256[] memory amounts = new uint256[](percentages.length);
        for (uint256 i = 0; i < percentages.length; i++) {
            vestingDays[i] = _today + _dates[vestingType][i];
            amounts[i] = (amount * percentages[i]) / 100;
        }
        return (amounts, vestingDays);
    }

    function today() public view returns (uint32) {
        return uint32(block.timestamp / 1 days);
    }
}

contracts/vesting/VestingStorage.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity =0.8.27;

import {
    IRegistry,
    IVestingStorage,
    VestingType,
    VestingRecord,
    BaseService,
    VESTING_HANDLER_ID,
    VESTING_STORAGE_ID
} from "../Index.sol";

contract VestingStorage is IVestingStorage, BaseService {
    struct Record {
        mapping(uint32 => uint256) amounts;
        uint32 firstDay;
        uint32 lastDay;
    }
    struct Table {
        mapping(uint256 tid => mapping(uint256 gid => mapping(address => Record))) records;
    }

    mapping(VestingType => Table) private _tables;

    /// @notice Modifier to restrict access to the current Vesting Handler
    modifier onlyHandler() {
        require(_registry.getAddress(VESTING_HANDLER_ID) == msg.sender, "VestingStorage: handler only");
        _;
    }

    constructor(IRegistry registry) BaseService(registry, VESTING_STORAGE_ID) {}

    /// @inheritdoc IVestingStorage
    function increaseVestingAmounts(
        VestingType vestingType,
        uint256 tid,
        uint256 gid,
        address account,
        VestingRecord calldata record
    ) external override onlyHandler returns (uint256 totalAmount) {
        require(record.amounts.length > 0, "VestingStorage: empty input");
        require(record.amounts.length == record.vestingDays.length, "VestingStorage: length mismatch");
        if (record.vestingDays.length == 0) return 0;
        Record storage _record = _tables[vestingType].records[tid][gid][account];
        uint32 firstDay = _record.firstDay;
        uint32 lastDay = _record.lastDay;
        for (uint256 i = 0; i < record.amounts.length; i++) {
            if (record.amounts[i] == 0) continue;
            if (record.vestingDays[i] < firstDay || firstDay == 0) {
                firstDay = record.vestingDays[i];
            }
            if (record.vestingDays[i] > lastDay) {
                lastDay = record.vestingDays[i];
            }
            _record.amounts[record.vestingDays[i]] += record.amounts[i];
            totalAmount += record.amounts[i];
        }
        _record.firstDay = firstDay;
        _record.lastDay = lastDay;
    }

    /// @inheritdoc IVestingStorage
    function decreaseVestingAmounts(
        VestingType vestingType,
        uint256 tid,
        uint256 gid,
        address account,
        VestingRecord calldata record,
        bool allowPartial
    ) external override onlyHandler returns (uint256 totalAmount) {
        require(record.amounts.length > 0, "VestingStorage: empty input");
        require(record.amounts.length == record.vestingDays.length, "VestingStorage: length mismatch");
        if (record.vestingDays.length == 0) return 0;
        Record storage _record = _tables[vestingType].records[tid][gid][account];
        for (uint256 i = 0; i < record.amounts.length; i++) {
            if (record.amounts[i] == 0) continue;
            uint256 currentAmount = _record.amounts[record.vestingDays[i]];
            require(currentAmount >= record.amounts[i], "VestingStorage: insufficient");
            require(allowPartial || currentAmount == record.amounts[i], "VestingStorage: partial decrease");
            _record.amounts[record.vestingDays[i]] = currentAmount - record.amounts[i];
            totalAmount += record.amounts[i];
        }
    }

    /// @inheritdoc IVestingStorage
    function getVestingAmounts(
        VestingType vestingType,
        uint256 tid,
        uint256 gid,
        address account,
        uint32[] calldata vestingDays
    ) external view override returns (uint256[] memory amounts) {
        require(vestingDays.length > 0, "VestingStorage: empty input");
        for (uint256 i = 1; i < vestingDays.length; i++) {
            require(vestingDays[i] > vestingDays[i-1], "VestingStorage: vesting days must be strictly increasing");
        }
        amounts = new uint256[](vestingDays.length);
        Record storage _record = _tables[vestingType].records[tid][gid][account];
        for (uint256 i = 0; i < vestingDays.length; i++) {
            amounts[i] = _record.amounts[vestingDays[i]];
        }
    }

    /// @inheritdoc IVestingStorage
    function getRange(
        VestingType vestingType,
        uint256 tid,
        uint256 gid,
        address account
    ) external view returns (uint32, uint32) { 
        Record storage _record = _tables[vestingType].records[tid][gid][account];
        return (_record.firstDay, _record.lastDay);
    }
}
